/* =========================================
   Component Styles
   ========================================= */

.post .package_parts {

	/* l-section */

	.l-section {
		font-family: var(--body-font-family);
		font-weight: 400;
		color: var(--color-font);
	}

	/* c-title */

	.c-title {
		background-color: var(--color-primary);
		padding: var(--px60) var(--px20) var(--px80);
	}

	.c-title__txt {
		line-height: 1;
		display: flex;
		gap: var(--px12);
		flex-direction: column;
		align-items: center;
		text-align: center;
		margin: 0 auto;
		max-width: 1100px;
	}

	.c-title__en {
		font-family: var(--font-family02);
		font-size: var(--px14);
		font-weight: 400;
		color: var(--color-primary);
		display: block;
		width: fit-content;
		padding: 8px;
		min-width: var(--px80);
		border-radius: var(--px40);
		background-color: #fff;
	}

	.c-title__ja {
		font-family: var(--body-font-family);
		font-size: var(--px50);
		font-weight: 700;
		color: #fff;
		line-height: 1.4;
		letter-spacing: 0.1em;
	}

	.l-section__inner {
		max-width: 1100px;
		margin: 0 auto;
	}

	.l-section__wrap {
		padding: var(--px80) var(--px20);
		background-color: var(--color-secondary-tint);
	}
}
